machine_start_gcode:
;Print Mode:{idex_print_mode}
;LAYER_COUNT:{total_layer_count}
{if is_idex_printer}
M425 S1 ; Wiper Strip enabled
M430 Z0 F600 ; Head change ZHop settings
M431 E4 F3000 ; Head change Exit Retract settings
M432 E0 F3000 ; Head change Enter Retract settings
M433 E4 F3000 ; Head change Enter Prime settings
{if idex_print_mode == "normal" || idex_print_mode == "backup"}
M104 T{current_extruder} S{first_layer_temperature[0]} ; Set hotend temp (no wait)
G28 ;Home
G1 Y155 F3000;
M190 S60 ; set bed temp (wait)
M109 T{current_extruder} S{first_layer_temperature[0]} ; set final nozzle temp
G1 E10 F100
{else}
M104 T0 S{first_layer_temperature[0]} ; Set hotend temp (no wait)
M104 T1 S{first_layer_temperature[0]} ; Set hotend temp (no wait)
G28 ;Home
G1 Y155 F3000;
M190 S60 ; set bed temp (wait)
M109 T0 S{first_layer_temperature[0]} ; set final nozzle temp
M109 T1 S{first_layer_temperature[0]} ; set final nozzle temp
G1 E10 F100
{endif}
{else}
M104 S{first_layer_temperature[0]} ; Set hotend temp (no wait)
G28 ;Home
M190 S60 ; set bed temp (wait)
M109 T{current_extruder} S{first_layer_temperature[0]} ; set final nozzle temp
G1 E10 F100
{endif}

change_filament_gcode:
;CHANGE_FILAMENT
M107
G92 E0
T{next_extruder}
M109 S{temperature[current_extruder]}
G92 E0
